 11 | export interface IterationResult {
 12 |   hasToolUse: boolean;
 13 |   finalMessage: Anthropic.Message;
 14 | }
 15 | 
 16 | const MODEL = modelAtom.get();
 17 | 
 18 | class AgentTurn {
 19 |   private onStreamCreateFns: Array<(stream: MessageStream<null>) => void> = [];
 20 |   private onToolUseFns: Array<
 21 |     (
 22 |       toolUseId: string,
 23 |       toolName: string,
 24 |       toolInput: Record<string, any>,
 25 |       completed: boolean,
 26 |     ) => void
 27 |   > = [];
 28 |   onStreamCreate(fn: (stream: MessageStream<null>) => void) {
 29 |     this.onStreamCreateFns.push(fn);
 30 |   }
 31 |   onToolUse(
 32 |     fn: (
 33 |       toolUseId: string,
 34 |       toolName: string,
 35 |       toolInput: Record<string, any>,
 36 |       completed: boolean,
 37 |     ) => void,
 38 |   ) {
 39 |     this.onToolUseFns.push(fn);
 40 |   }
 41 |   async executeSingleIteration(): Promise<IterationResult> {
 42 |     const messages = messagesAtom.get();
 43 |     
 44 |     const stream = client.messages.stream({
 45 |       model: MODEL,
 46 |       max_tokens: 2048,
 47 |       system: systemPrompt,
 48 |       messages,
 49 |       tools: toolDefinitions,
 50 |     });
 51 |     this.onStreamCreateFns.forEach((fn) => fn(stream));
 52 |     let hasToolUse = false;
 53 |     const completedToolUses: Array<{ id: string; name: string; input: Record<string, any> }> = [];
 54 |     stream.on('contentBlock', (content) => {
 55 |       if (content.type === 'tool_use') {
 56 |         hasToolUse = true;
 57 |         completedToolUses.push({
 58 |           id: content.id,
 59 |           name: content.name,
 60 |           input: content.input as Record<string, any>,
 61 |         });
 62 |       }
 63 |     });
 64 |     // 等待流结束，获取完整消息
 65 |     const finalMessage = await stream.finalMessage();
 66 |     messagesAtom.set([...messages, finalMessage]);
 67 |     // 执行工具并收集结果
 68 |     if (completedToolUses.length > 0) {
 69 |       const toolResults: Anthropic.ToolResultBlockParam[] = [];
 70 |       for (const tool of completedToolUses) {
 71 |         let result: string;
 72 |         try {
 73 |           this.onToolUseFns.forEach((fn) => fn(tool.id, tool.name, tool.input, false));
 74 |           result = await executeTool(tool.name, tool.input);
 75 |         } catch (error) {
 76 |           const message =
 77 |             error instanceof Error ? `${error.name}: ${error.message}` : String(error);
 78 |           result = `工具 ${tool.name} 执行异常：\n${message}`;
 79 |         }
 80 |         toolResults.push({
 81 |           type: 'tool_result',
 82 |           tool_use_id: tool.id,
 83 |           content: result,
 84 |         });
 85 |         this.onToolUseFns.forEach((fn) => fn(tool.id, tool.name, tool.input, true));
 86 |       }
 87 |       messagesAtom.set([
 88 |         ...messagesAtom.get(),
 89 |         {
 90 |           role: 'user',
 91 |           content: toolResults,
 92 |         },
 93 |       ]);
 94 |     }
 95 | 
 96 |     return { hasToolUse, finalMessage };
 97 |   }
 98 |   async run(userInput: string, onIteration?: (result: IterationResult) => void) {
 99 |     messagesAtom.set([...messagesAtom.get(), { role: 'user', content: userInput }]);
100 |     while (true) {
101 |       const result = await this.executeSingleIteration();
102 |       onIteration?.(result);
103 |       if (!result.hasToolUse) return;
104 |     }
105 |   }
106 | }
