 4 | /**
 5 |  * 将 messages 重新处理，减少噪声。
 6 |  * 策略：只保留最近 3 个对话的工具执行结果的完整内容，
 7 |  * 旧工具结果只保留工具名称，内容截断。
 8 |  */
 9 | const MAX_FULL_TOOL_RESULTS = 3;
10 | const MAX_TOOL_RESULT_LENGTH = 10000; // 超过部分截断
11 | 
12 | export class AutoCompactPlugin extends MicaPlugin {
13 |   onInstall(): void {
14 |     const originalRun = this.agent.agentTurn.run.bind(this.agent.agentTurn);
15 |     const getMessages = () => this.store.messages.get();
16 | 
17 |     this.agent.agentTurn.run = async function (
18 |       userInput: string,
19 |       callbacks?: Parameters<typeof originalRun>[1],
20 |     ) {
21 |       compactMessages(getMessages());
22 |       return originalRun(userInput, callbacks);
23 |     };
24 |   }
25 | }
26 | 
27 | function compactMessages(messages: Anthropic.MessageParam[]) {
28 |   // 构建 tool_use_id → tool_name 映射
29 |   const toolNameMap = new Map<string, string>();
30 |   for (const msg of messages) {
31 |     if (msg.role !== 'assistant' || !Array.isArray(msg.content)) continue;
32 |     for (const block of msg.content) {
33 |       if (block.type === 'tool_use') {
34 |         toolNameMap.set(block.id, block.name);
35 |       }
36 |     }
37 |   }
38 | 
39 |   let toolResultCount = 0;
40 | 
41 |   // 从最新到最旧遍历，保留最近 N 个完整结果，其余截断
42 |   for (let i = messages.length - 1; i >= 0; i--) {
43 |     const msg = messages[i];
44 |     if (msg.role !== 'user' || !Array.isArray(msg.content)) continue;
45 |     for (const block of msg.content) {
46 |       if (block.type !== 'tool_result') continue;
47 |       toolResultCount++;
48 |       if (typeof block.content === 'string' && block.content.length > MAX_TOOL_RESULT_LENGTH) {
49 |         block.content =
50 |           block.content.substring(0, MAX_TOOL_RESULT_LENGTH) + '\n[已截断] 工具结果过长已被截断';
51 |       }
52 |       if (toolResultCount > MAX_FULL_TOOL_RESULTS) {
53 |         const toolName = toolNameMap.get(block.tool_use_id) || 'unknown';
54 |         if (typeof block.content === 'string') {
55 |           block.content = `[已截断] 工具 ${toolName} 结果已截断以节省上下文`;
56 |         }
57 |       }
58 |     }
59 |   }
60 | }
