 6 | // ── Retry configuration ──
 7 | 
 8 | const RETRY_MAX_ATTEMPTS = 3;
 9 | const RETRY_BASE_DELAY_MS = 1_000;
10 | const RETRY_MAX_DELAY_MS = 30_000;
11 | 
12 | function isRetryable(error: unknown): boolean {
13 |   if (error instanceof Anthropic.RateLimitError) return true;
14 |   if (error instanceof Anthropic.APIConnectionError) return true;
15 |   if (error instanceof Anthropic.APIConnectionTimeoutError) return true;
16 |   if (error instanceof Anthropic.InternalServerError) return true;
17 |   if (error instanceof Anthropic.APIUserAbortError) return false;
18 |   // 其他（认证错误、非法请求等）不重试
19 |   return false;
20 | }
