22 | /**
23 |  * 错误重试插件：当 API 调用遇到可重试错误时自动重试。
24 |  */
25 | export class ErrorHandlerPlugin extends MicaPlugin {
26 |   onInstall(): void {
27 |     const originalRun = this.agent.agentTurn.run.bind(this.agent.agentTurn);
28 |     const store = this.store;
29 |     const showStatus = this.showStatus;
30 |     this.agent.agentTurn.run = async function (
31 |       userInput: string,
32 |       onIteration?: (result: IterationResult) => void,
33 |     ) {
34 |       // 外层重试：当一轮完整对话（可能包含多次工具调用）因网络错误失败时重试
35 |       let attempt = 0;
36 |       while (attempt < RETRY_MAX_ATTEMPTS) {
37 |         try {
38 |           return await originalRun(userInput, onIteration);
39 |         } catch (error) {
40 |           attempt++;
41 |           if (!isRetryable(error) || attempt >= RETRY_MAX_ATTEMPTS) throw error;
42 |           const delay = Math.min(RETRY_BASE_DELAY_MS * 2 ** attempt, RETRY_MAX_DELAY_MS);
