 31 | /**
 32 |  * 聊天历史插件：
 33 |  * - 用户按下 Enter 提交文本后，将文本保存在历史中（最多 10 条）。
 34 |  * - 用户按上/下箭头（在输入框首行/末行时）可以切换历史记录。
 35 |  * - 切换时更新 statusesAtom 显示当前所在历史位置。
 36 |  * - 历史记录持久化到 ~/.mica/mica_chat_history
 37 |  */
 38 | export class ChatHistoryPlugin extends MicaPlugin {
 39 |   private history: string[] = [];
 40 |   private historyIndex = -1;
 41 |   private currentInput = '';
 42 | 
 43 |   async onInstall(): Promise<void> {
 44 |     // 立即从磁盘加载历史记录，确保重启后立即可用
 45 |     this.history = await loadHistory();
 46 | 
 47 |     const updateStatus = () => {
 48 |       if (this.historyIndex < 0) {
 49 |         this.removeStatus(HISTORY_STATUS_ID);
 50 |       } else {
 51 |         this.showStatus(`历史记录 ${this.historyIndex + 1}/${this.history.length}`);
 52 |       }
 53 |     };
 54 | 
 55 |     this.registerInputHandler((_char, key, ctx) => {
 56 |       if (ctx.showDropdown) return false;
 57 | 
 58 |       if (key.upArrow) {
 59 |         if (ctx.currentRow !== 0) return false;
 60 |         if (this.history.length === 0) return true;
 61 | 
 62 |         if (this.historyIndex === -1) {
 63 |           this.currentInput = ctx.inputValue;
 64 |         }
 65 | 
 66 |         this.historyIndex = Math.min(this.historyIndex + 1, this.history.length - 1);
 67 |         const text = this.history[this.history.length - 1 - this.historyIndex];
 68 |         ctx.dispatch({ type: 'clear' });
 69 |         ctx.dispatch({ type: 'insert', text });
 70 |         ctx.dispatch({ type: 'move', cursor: text.length });
 71 |         updateStatus();
 72 |         return true;
 73 |       }
 74 | 
 75 |       if (key.downArrow) {
 76 |         if (ctx.currentRow !== ctx.totalRows - 1) return false;
 77 |         if (this.historyIndex < 0) return false;
 78 | 
 79 |         this.historyIndex--;
 80 |         if (this.historyIndex < 0) {
 81 |           ctx.dispatch({ type: 'clear' });
 82 |           ctx.dispatch({ type: 'insert', text: this.currentInput });
 83 |           ctx.dispatch({ type: 'move', cursor: this.currentInput.length });
 84 |           this.currentInput = '';
 85 |           updateStatus();
 86 |           return true;
 87 |         }
 88 | 
 89 |         const text = this.history[this.history.length - 1 - this.historyIndex];
 90 |         ctx.dispatch({ type: 'clear' });
 91 |         ctx.dispatch({ type: 'insert', text });
 92 |         ctx.dispatch({ type: 'move', cursor: text.length });
 93 |         updateStatus();
 94 |         return true;
 95 |       }
 96 | 
 97 |       if (this.historyIndex >= 0 && _char) {
 98 |         this.historyIndex = -1;
 99 |         this.currentInput = '';
100 |         updateStatus();
101 |       }
102 | 
103 |       return false;
104 |     });
105 | 
106 |     // 保存每次提交的消息到历史记录
107 |     const originalRun = this.agent.agentTurn.run.bind(this.agent.agentTurn);
108 | 
109 |     this.agent.agentTurn.run = async (userInput: string, callbacks?: any) => {
110 |       if (this.history.length === 0 || this.history[this.history.length - 1] !== userInput) {
111 |         this.history.push(userInput);
112 |         if (this.history.length > MAX_HISTORY) {
113 |           this.history.shift();
114 |         }
115 |         saveHistory(this.history);
116 |       }
117 | 
118 |       this.historyIndex = -1;
119 |       this.currentInput = '';
120 |       updateStatus();
121 | 
122 |       return originalRun(userInput, callbacks);
123 |     };
124 |   }
125 | }
