 3 | export function inputReducer(state: InputState, action: InputAction): InputState {
 4 |   switch (action.type) {
 5 |     case 'insert':
 6 |       return {
 7 |         value: state.value.slice(0, state.cursor) + action.text + state.value.slice(state.cursor),
 8 |         cursor: state.cursor + action.text.length,
 9 |       };
10 |     case 'backspace':
11 |       if (state.cursor === 0) return state;
12 |       return {
13 |         value: state.value.slice(0, state.cursor - 1) + state.value.slice(state.cursor),
14 |         cursor: state.cursor - 1,
15 |       };
16 |     case 'delete':
17 |       if (state.cursor >= state.value.length) return state;
18 |       return {
19 |         value: state.value.slice(0, state.cursor) + state.value.slice(state.cursor + 1),
20 |         cursor: state.cursor,
21 |       };
22 |     case 'clear':
23 |       return { value: '', cursor: 0 };
24 |     case 'move':
25 |       return { ...state, cursor: action.cursor };
26 |   }
27 | }
